import { FormItem, Form } from '@/components/ui/Form'
import Input from '@/components/ui/Input'
import Button from '@/components/ui/Button'
import Select from '@/components/ui/Select'
import DatePicker from '@/components/ui/DatePicker'
import TimeInput from '@/components/ui/TimeInput'
import Checkbox from '@/components/ui/Checkbox'
import Radio from '@/components/ui/Radio'
import Switcher from '@/components/ui/Switcher'
import Segment from '@/components/ui/Segment'
import Slider from '@/components/ui/Slider'
import Upload from '@/components/ui/Upload'
import { HiCheckCircle } from 'react-icons/hi'
import classNames from '@/utils/classNames'
import { useForm, Controller } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { z } from 'zod'


type Option = {
    value: string
    label: string
}

type FormSchema = {
    input: string
    select: string
    multipleSelect: Option[]
    date: Date | null
    time: Date | null
    singleCheckbox: boolean
    multipleCheckbox: Array<string | number>
    radio: string
    switcher: boolean
    segment: string[]
    upload: File[]
    slider: number
}

const options: Option[] = [
    { value: 'foo', label: 'Foo' },
    { value: 'bar', label: 'Bar' },
]

const segmentSelections = [
    { value: 'Personal', desc: 'The plan for personal.' },
    { value: 'Team', desc: 'The plan for team' },
    { value: 'Business', desc: 'Talk to us for business plan.' },
]

const MAX_UPLOAD = 2

const validationSchema = z.object({
    input: z
        .string()
        .min(1, 'Please input user name!')
        .min(3, 'Too Short!')
        .max(12, 'Too Long!'),
    select: z.string().min(1, 'Please select one!'),
    multipleSelect: z
        .array(z.object({ value: z.string(), label: z.string() }))
        .nonempty('At least one is selected!'),
    date: z.date({
        error: (issue) => {
            if (issue.code === 'invalid_type') {
                return 'Invalid Date'
            }
            return 'Date Required!'
        },
    }).nullable(),
    time: z.date({
        error: (issue) => {
            if (issue.code === 'invalid_type') {
                return 'Invalid Time'
            }
            return 'Time Required!'
        },
    }).nullable(),
    singleCheckbox: z.literal<boolean>(true, { error: () => ({ message: 'You must turn this on!' }) }),
    multipleCheckbox: z
        .array(z.union([z.string(), z.number()]))
        .nonempty('Select at least one option!'),
    radio: z.string().min(1, 'Please select one!'),
    switcher: z.literal<boolean>(true, { error: () => ({ message: 'You must turn this on!' }) }),
    upload: z.array(z.instanceof(File)).nonempty('At least one file uploaded!'),
    slider: z.number().min(1, 'Minimum value is 1').max(100, 'Maximum value is 100'),
    segment: z.array(z.string()).nonempty('Select at least one option!'),
})

const MixedFormControl = () => {
    const {
        handleSubmit,
        reset,
        formState: { errors, isSubmitting },
        control,
    } = useForm<FormSchema>({
        defaultValues: {
            input: '',
            select: '',
            date: null,
            time: null,
            multipleSelect: [],
            singleCheckbox: false,
            multipleCheckbox: [],
            radio: '',
            switcher: false,
            segment: [],
            upload: [],
            slider: 0
        },
        resolver: zodResolver(validationSchema),
    })

    const beforeUpload = (file: FileList | null, fileList: File[]) => {
        let valid: string | boolean = true

        const allowedFileType = ['image/jpeg', 'image/png']
        const MAX_FILE_SIZE = 500000

        if (fileList.length >= MAX_UPLOAD) {
            return `You can only upload ${MAX_UPLOAD} file(s)`
        }

        if (file) {
            for (const f of file) {
                if (!allowedFileType.includes(f.type)) {
                    valid = 'Please upload a .jpeg or .png file!'
                }

                if (f.size >= MAX_FILE_SIZE) {
                    valid = 'Upload image cannot more then 500kb!'
                }
            }
        }

        return valid
    }

    const onSubmit = (values: FormSchema) => {
        setTimeout(() => {
            alert(JSON.stringify(values, null, 2))
        }, 400)
    }

    return (
